import xml.etree.ElementTree as ET

def parse_config_xml(file_path):
    """
    Parse an XML configuration file and return settings as a dictionary.
    
    Args:
        file_path (str): Path to the XML configuration file
        
    Returns:
        dict: Dictionary containing configuration settings
    """
    tree = ET.parse(file_path)
    root = tree.getroot()
    
    settings = {}
    
    for child in root:
        if len(child) == 0:  # Leaf element
            settings[child.tag] = child.text
        else:  # Element with children
            settings[child.tag] = {}
            for subchild in child:
                settings[child.tag][subchild.tag] = subchild.text
    
    return settings